// Vanguard Insurance Software - Main Application JavaScript

// Global variables

// Function to load policies from server
async function loadPoliciesFromServer() {
    try {
        console.log('Loading policies from server...');
        const response = await fetch('/api/policies?limit=1000'); // Get more policies
        if (response.ok) {
            const serverPolicies = await response.json();
            console.log(`Loaded ${serverPolicies.length} policies from server`);

            // Merge: preserve local clientId/clientName when server doesn't have them
            const existingLocal = JSON.parse(localStorage.getItem('insurance_policies') || '[]');
            const localById = {};
            existingLocal.forEach(p => { if (p.id) localById[p.id] = p; });
            const mergedPolicies = serverPolicies.map(sp => {
                const lp = localById[sp.id];
                if (!lp) return sp;
                const merged = { ...sp };
                if (!sp.clientId && lp.clientId) { merged.clientId = lp.clientId; merged.clientName = lp.clientName || sp.clientName; }
                if (!sp.contact?.['Owner Name'] && lp.contact?.['Owner Name']) merged.contact = { ...lp.contact, ...sp.contact };
                return merged;
            });
            localStorage.setItem('insurance_policies', JSON.stringify(mergedPolicies));
            console.log('✅ Policies synced to localStorage (clientId preserved)');

            return serverPolicies;
        } else {
            console.error('Failed to load policies:', response.status);
            return JSON.parse(localStorage.getItem('insurance_policies') || '[]');
        }
    } catch (error) {
        console.error('Error loading policies from server:', error);
        // Fallback to localStorage
        return JSON.parse(localStorage.getItem('insurance_policies') || '[]');
    }
}

// Function to load leads from server and filter out archived
async function loadLeadsFromServer() {
    try {
        console.log('Loading leads from server...');
        const response = await fetch('/api/leads');
        if (response.ok) {
            const serverLeads = await response.json();
            console.log(`Loaded ${serverLeads.length} leads from server`);

            // Get existing archived leads from localStorage to preserve archive status
            const existingLeads = JSON.parse(localStorage.getItem('insurance_leads') || '[]');
            const existingArchived = JSON.parse(localStorage.getItem('archivedLeads') || '[]');

            // Create a map of archived lead IDs for quick lookup
            const archivedIds = new Set();
            existingArchived.forEach(lead => archivedIds.add(String(lead.id)));
            existingLeads.forEach(lead => {
                if (lead.archived === true) {
                    archivedIds.add(String(lead.id));
                }
            });

            // Update server leads with archived status from local storage
            const mergedLeads = serverLeads.map(serverLead => {
                // SPECIAL PROTECTION: Never archive ViciDial leads unless explicitly archived by user
                if (serverLead.source === 'ViciDial') {
                    // Only mark as archived if explicitly set in database, not from localStorage
                    if (serverLead.archived !== true && serverLead.archived !== 1) {
                        serverLead.archived = false;
                        console.log(`🛡️ PROTECTING ViciDial lead from archival: ${serverLead.id} - ${serverLead.name}`);
                    }
                } else {
                    // For non-ViciDial leads, check if this lead was previously archived
                    if (archivedIds.has(String(serverLead.id))) {
                        serverLead.archived = true;
                        console.log(`Preserving archived status for lead ${serverLead.id} - ${serverLead.name}`);
                    }
                }
                return serverLead;
            });

            // Filter out archived leads for display
            const activeLeads = mergedLeads.filter(lead => !lead.archived);
            console.log(`Found ${activeLeads.length} active leads after filtering ${archivedIds.size} archived`);

            // CRITICAL: Complete separation - archived leads should NEVER be in insurance_leads
            const permanentArchive = JSON.parse(localStorage.getItem('PERMANENT_ARCHIVED_IDS') || '[]');
            const activeLeadsOnly = mergedLeads.filter(lead =>
                !lead.archived &&
                !permanentArchive.includes(String(lead.id)) &&
                !archivedIds.has(String(lead.id))
            );
            const archivedLeadsOnly = mergedLeads.filter(lead =>
                lead.archived === true ||
                permanentArchive.includes(String(lead.id)) ||
                archivedIds.has(String(lead.id))
            );

            // Special handling for ViciDial leads - ensure they're never accidentally filtered
            const vicidialLeads = mergedLeads.filter(lead =>
                lead.source === 'ViciDial' &&
                !lead.archived &&
                !permanentArchive.includes(String(lead.id)) &&
                !archivedIds.has(String(lead.id))
            );

            if (vicidialLeads.length > 0) {
                console.log(`⚠️ PRESERVING ${vicidialLeads.length} ViciDial leads:`, vicidialLeads.map(l => `${l.id} - ${l.name}`));
            }

            // Initialize reachOut object for all leads before saving
            activeLeadsOnly.forEach(lead => {
                if (!lead.reachOut) {
                    lead.reachOut = {
                        callAttempts: 0,
                        callsConnected: 0,
                        emailCount: 0,
                        textCount: 0,
                        voicemailCount: 0
                    };
                }
            });

            // SMART MERGE: Use smart merge instead of direct overwrite to preserve recent changes
            console.log(`🔍 SERVER DEBUG: About to save ${activeLeadsOnly.length} active leads to localStorage`);
            if (activeLeadsOnly.length === 1) {
                console.error(`❌ SERVER PROBLEM: Only 1 active lead from server!`, activeLeadsOnly[0].id, activeLeadsOnly[0].name);
            }

            console.log('🧠 loadLeadsFromServer: Using SMART MERGE to preserve recent changes...');
            if (typeof window.manualSyncLeads === 'function') {
                // Use existing smart merge if available
                await window.manualSyncLeads();
            } else {
                // Fallback: preserve recent changes manually
                const existingLeads = JSON.parse(localStorage.getItem('insurance_leads') || '[]');
                const smartMergedLeads = [...existingLeads];
                const now = Date.now();
                const deletedIds = new Set(JSON.parse(localStorage.getItem('DELETED_LEAD_IDS') || '[]').map(String));

                let addedCount = 0;
                let preservedCount = 0;
                let updatedCount = 0;

                activeLeadsOnly.forEach(serverLead => {
                    // Skip leads the user has explicitly deleted
                    if (deletedIds.has(String(serverLead.id))) {
                        return;
                    }

                    const localIndex = smartMergedLeads.findIndex(localLead =>
                        String(localLead.id) === String(serverLead.id)
                    );

                    if (localIndex === -1) {
                        // New lead from server
                        smartMergedLeads.push(serverLead);
                        addedCount++;
                    } else {
                        const localLead = smartMergedLeads[localIndex];

                        // Check if lead has recent local changes (within 10 minutes)
                        const hasRecentChanges = localLead.lastModified &&
                            (now - new Date(localLead.lastModified).getTime()) < (10 * 60 * 1000);

                        // Check for important field changes
                        const hasStageChange = localLead.stage !== serverLead.stage;
                        const hasNotesChange = localLead.notes !== serverLead.notes;

                        if (hasRecentChanges || hasStageChange || hasNotesChange) {
                            console.log(`🛡️ loadLeadsFromServer: Preserving recent changes for lead ${localLead.id}`);
                            // Preserve local changes, but allow some server updates
                            smartMergedLeads[localIndex] = {
                                ...serverLead,  // Server data as base
                                ...localLead,   // Local changes override
                                // Keep local timestamp to track our changes
                                lastModified: localLead.lastModified || new Date().toISOString()
                            };
                            preservedCount++;
                        } else {
                            // No recent local changes - safe to update with server data
                            smartMergedLeads[localIndex] = {
                                ...localLead,
                                ...serverLead,
                                lastModified: new Date().toISOString()
                            };
                            updatedCount++;
                        }
                    }
                });

                console.log(`🧠 loadLeadsFromServer SMART MERGE: Added ${addedCount}, Preserved ${preservedCount}, Updated ${updatedCount}`);
                // Try saving full data; if quota exceeded, slim down callLogs and retry
                try {
                    localStorage.setItem('insurance_leads', JSON.stringify(smartMergedLeads));
                } catch (quotaErr) {
                    console.warn('⚠️ localStorage quota exceeded - trimming callLogs and retrying...');
                    const slimmed = smartMergedLeads.map(lead => {
                        if (!lead.reachOut || !lead.reachOut.callLogs) return lead;
                        return {
                            ...lead,
                            reachOut: {
                                ...lead.reachOut,
                                callLogs: lead.reachOut.callLogs.slice(-25) // keep only last 25 per lead
                            }
                        };
                    });
                    try {
                        localStorage.setItem('insurance_leads', JSON.stringify(slimmed));
                        console.log('✅ Saved slimmed leads to localStorage');
                    } catch (e2) {
                        console.error('❌ localStorage still full after trimming - skipping localStorage save, using server data in memory only');
                    }
                }
            }

            // Update archived leads storage
            const archivedLeads = archivedLeadsOnly; // Rename for compatibility

            // Initialize reachOut object for archived leads as well
            archivedLeads.forEach(lead => {
                if (!lead.reachOut) {
                    lead.reachOut = {
                        callAttempts: 0,
                        callsConnected: 0,
                        emailCount: 0,
                        textCount: 0,
                        voicemailCount: 0
                    };
                }
            });

            if (archivedLeads.length > 0) {
                localStorage.setItem('archivedLeads', JSON.stringify(archivedLeads));

                // Save archived status back to server for leads that don't have it yet
                archivedLeads.forEach(lead => {
                    fetch('/api/leads', {
                        method: 'POST',
                        headers: {
                            'Content-Type': 'application/json'
                        },
                        body: JSON.stringify(lead)
                    })
                    .then(response => response.json())
                    .then(data => {
                        console.log(`Saved archived status for lead ${lead.id} to server`);
                    })
                    .catch(error => {
                        console.error(`Failed to save archived status for lead ${lead.id}:`, error);
                    });
                });
            }

            console.log(`✅ Server leads synchronized: ${activeLeadsOnly.length} active, ${archivedLeadsOnly.length} archived`);

            // Refresh leads display if we're on the leads page
            if (window.location.hash === '#leads') {
                console.log('🔄 Refreshing leads display after server sync');
                if (typeof displayLeads === 'function') {
                    displayLeads();
                }
            }
        }
    } catch (error) {
        console.error('Failed to load leads from server:', error);
        // Fall back to localStorage data if server fails
    }
}

// Function to load clients from server and sync with localStorage
async function loadClientsFromServer(limit = 500) {
    try {
        console.log('💻 Loading clients from server...');
        const response = await fetch(`/api/clients?limit=${limit}&offset=0`);

        console.log('📡 Server response status:', response.status);

        if (response.ok) {
            const data = await response.json();
            console.log('📊 Server response data type:', Array.isArray(data) ? 'array' : 'object');

            // Handle both old format (array) and new format (object with clients array)
            let serverClients;
            let totalCount;

            if (Array.isArray(data)) {
                // Old format - direct array
                serverClients = data;
                totalCount = data.length;
            } else {
                // New paginated format
                serverClients = data.clients || [];
                totalCount = data.total || serverClients.length;
            }

            console.log(`✅ Server returned ${serverClients.length} clients (total: ${totalCount})`);

            if (serverClients.length > 0) {
                console.log('📝 Sample client names:', serverClients.slice(0, 3).map(c => c.name));
            }

            // USER-SPECIFIC FILTERING: Maureen can only see her assigned clients
            const currentUserData = localStorage.getItem('user');
            if (currentUserData) {
                const user = JSON.parse(currentUserData);
                console.log('🔍 CLIENT FILTER DEBUG: Current user:', user.username);
                if (user.username && user.username.toLowerCase() === 'maureen') {
                    const originalCount = serverClients.length;
                    console.log('🔍 BEFORE CLIENT FILTER: Sample client assignments:', serverClients.slice(0, 5).map(c => `${c.name}: ${c.assignedTo || 'unassigned'}`));
                    serverClients = serverClients.filter(client =>
                        client.assignedTo === 'Maureen' ||
                        client.assignedTo === 'maureen' ||
                        (client.agent && (client.agent === 'Maureen' || client.agent === 'maureen'))
                    );
                    console.log(`🔒 MAUREEN CLIENT FILTER: ${originalCount} → ${serverClients.length} clients (showing only Maureen's assigned clients)`);
                    console.log('🔍 AFTER CLIENT FILTER: Remaining clients:', serverClients.map(c => `${c.name}: ${c.assignedTo || c.agent || 'unassigned'}`));
                }
            }

            // Merge: keep local-only clients (IVANS-created) not yet on server
            const existingLocalClients = JSON.parse(localStorage.getItem('insurance_clients') || '[]');
            const serverClientIds = new Set(serverClients.map(c => String(c.id)));
            const localOnlyClients = existingLocalClients.filter(c => c.id && !serverClientIds.has(String(c.id)));
            const mergedClients = [...serverClients, ...localOnlyClients];

            // === Suppress business-name-only duplicate records ===
            // E.g. "CHRIS STEVENS TRUCKING LLC" is suppressed because person client
            // "Christopher Stevens" already has businessName = "Chris Stevens Trucking LLC".
            const _BIZ_RE   = /\b(llc|l\.l\.c|inc|incorporated|corp|corporation|ltd|limited|lp|l\.p|trucking|transport|transportation|logistics|hauling|construction|farms|enterprises|services|solutions|towing)\b/i;
            const _isBizOnly = (c) => _BIZ_RE.test(c.name || '');
            const _nb        = (s) => (s || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, ' ').trim();
            const _np        = (ph) => (ph || '').replace(/\D/g, '');

            const _pBizKeys = new Set();
            const _pPhones  = new Set();
            mergedClients.forEach(c => {
                if (_isBizOnly(c)) return;
                if (c.businessName) _pBizKeys.add(_nb(c.businessName));
                const ph = _np(c.phone);
                if (ph.length >= 10) _pPhones.add(ph);
            });
            const _toSuppress = new Set();
            mergedClients.forEach(c => {
                if (!_isBizOnly(c)) return;
                const bk = _nb(c.name);
                const ph = _np(c.phone);
                if ((bk && _pBizKeys.has(bk)) || (ph.length >= 10 && _pPhones.has(ph))) {
                    _toSuppress.add(String(c.id));
                }
            });
            const dedupedClients = _toSuppress.size > 0
                ? mergedClients.filter(c => !_toSuppress.has(String(c.id)))
                : mergedClients;

            localStorage.setItem('insurance_clients', JSON.stringify(dedupedClients));
            console.log(`💾 Stored ${dedupedClients.length} clients in localStorage (${mergedClients.length - dedupedClients.length} biz-name dupes suppressed, ${localOnlyClients.length} local-only preserved)`);

            // Store pagination info for later use
            if (data.total) {
                localStorage.setItem('clients_total_count', data.total.toString());
                localStorage.setItem('clients_has_more', data.hasMore ? 'true' : 'false');
            }

            console.log('✅ Server clients synchronized successfully');
            return serverClients;
        } else {
            console.error('❌ Server response not ok:', response.status, response.statusText);
            console.log('❌ Will retry with empty array since localStorage was likely cleared');
            // Don't return localStorage fallback if we're trying to recover from cleared storage
            return [];
        }
    } catch (error) {
        console.error('💥 Failed to load clients from server:', error);
        // If localStorage is empty, try one more time after a brief delay
        const fallbackClients = JSON.parse(localStorage.getItem('insurance_clients') || '[]');
        if (fallbackClients.length === 0) {
            console.log('💥 Server failed and localStorage empty - will retry in 2 seconds...');
            setTimeout(async () => {
                try {
                    console.log('🔄 Retry attempt...');
                    await loadClientsFromServer();
                    if (window.location.hash === '#clients') {
                        loadClientsView();
                    }
                } catch (retryError) {
                    console.error('💥 Retry also failed:', retryError);
                }
            }, 2000);
        }
        console.log(`📦 Using localStorage fallback after error: ${fallbackClients.length} clients`);
        return fallbackClients;
    }
}

// Function to update the clients footer information
function updateClientsFooterInfo() {
    const showingInfo = document.getElementById('clientsShowingInfo');
    const pagination = document.getElementById('clientsPagination');

    if (!showingInfo) return;

    const clients = JSON.parse(localStorage.getItem('insurance_clients') || '[]');
    const totalCount = localStorage.getItem('clients_total_count');
    const hasMore = localStorage.getItem('clients_has_more') === 'true';

    const displayedCount = clients.length;
    const totalText = totalCount ? ` of ${parseInt(totalCount).toLocaleString()}` : '';

    showingInfo.textContent = `Showing ${displayedCount.toLocaleString()}${totalText} clients`;

    // Add "Load More" button if there are more clients to load
    if (pagination && hasMore && totalCount && displayedCount < parseInt(totalCount)) {
        pagination.innerHTML = `
            <button class="btn-secondary" onclick="loadMoreClients()" id="loadMoreClientsBtn">
                <i class="fas fa-plus"></i> Load More Clients
            </button>
        `;
    } else if (pagination) {
        pagination.innerHTML = '';
    }
}

// Function to load more clients from server
async function loadMoreClients() {
    const currentClients = JSON.parse(localStorage.getItem('insurance_clients') || '[]');
    const loadMoreBtn = document.getElementById('loadMoreClientsBtn');

    if (loadMoreBtn) {
        loadMoreBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Loading More...';
        loadMoreBtn.disabled = true;
    }

    try {
        const response = await fetch(`/api/clients?limit=500&offset=${currentClients.length}`);
        if (response.ok) {
            const data = await response.json();
            const newClients = data.clients || [];

            if (newClients.length > 0) {
                // Append new clients to existing ones
                const allClients = [...currentClients, ...newClients];
                localStorage.setItem('insurance_clients', JSON.stringify(allClients));

                // Update pagination info
                localStorage.setItem('clients_has_more', data.hasMore ? 'true' : 'false');

                // Refresh the table
                const tbody = document.getElementById('clientsTableBody');
                if (tbody) {
                    tbody.innerHTML = '<tr><td colspan="7" style="text-align: center; padding: 20px;"><i class="fas fa-spinner fa-spin"></i> Syncing clients...</td></tr>';
                    generateClientRows(1).then(content => {
                        tbody.innerHTML = content;
                    }).catch(error => {
                        console.error('Error generating client rows:', error);
                        tbody.innerHTML = '<tr><td colspan="7" style="text-align: center; padding: 20px; color: #dc2626;">Error loading clients</td></tr>';
                    });
                }

                // Update footer info
                updateClientsFooterInfo();

                console.log(`Loaded ${newClients.length} more clients. Total: ${allClients.length}`);
            }
        }
    } catch (error) {
        console.error('Failed to load more clients:', error);
    }

    if (loadMoreBtn) {
        loadMoreBtn.innerHTML = '<i class="fas fa-plus"></i> Load More Clients';
        loadMoreBtn.disabled = false;
    }
}

// Global function to clean up any duplicate leads
function cleanupDuplicateLeads() {
    console.log('Running global duplicate cleanup...');

    const archivedLeads = JSON.parse(localStorage.getItem('archivedLeads') || '[]');
    const permanentArchive = JSON.parse(localStorage.getItem('PERMANENT_ARCHIVED_IDS') || '[]');
    const allLeads = JSON.parse(localStorage.getItem('insurance_leads') || '[]');

    // Build set of archived identifiers
    const archivedIds = new Set();
    const archivedPhones = new Set();
    const archivedEmails = new Set();

    // Add permanent archive IDs - these are NEVER allowed in active list
    permanentArchive.forEach(id => {
        archivedIds.add(String(id));
    });

    archivedLeads.forEach(lead => {
        archivedIds.add(String(lead.id));
        if (lead.phone) archivedPhones.add(lead.phone.replace(/\D/g, ''));
        if (lead.email) archivedEmails.add(lead.email.toLowerCase());
    });

    let cleanedCount = 0;

    // Clean the main leads list
    const cleanedLeads = allLeads.map(lead => {
        // If this lead matches ANY archived identifier, mark it as archived
        if (archivedIds.has(String(lead.id)) ||
            (lead.phone && archivedPhones.has(lead.phone.replace(/\D/g, ''))) ||
            (lead.email && archivedEmails.has(lead.email.toLowerCase()))) {

            if (!lead.archived) {
                lead.archived = true;
                cleanedCount++;
                console.log(`Cleanup: Marked lead as archived: ${lead.id} - ${lead.name}`);
            }
        }
        return lead;
    });

    if (cleanedCount > 0) {
        localStorage.setItem('insurance_leads', JSON.stringify(cleanedLeads));
        console.log(`Cleanup complete: Fixed ${cleanedCount} leads that should have been archived`);

        // Only refresh if on leads page AND view has already loaded (prevent race condition)
        if ((window.location.hash === '#leads' || window.location.hash === '#leads-management') &&
            document.querySelector('.leads-view') &&
            typeof loadLeadsView === 'function') {

            // Debounce to prevent rapid refreshes
            clearTimeout(window.leadsRefreshTimeout);
            window.leadsRefreshTimeout = setTimeout(() => {
                loadLeadsView();
            }, 1000);
        }
    } else {
        console.log('Cleanup complete: No duplicates found');
    }
}

// One-time cleanup to completely separate archived and active leads
function oneTimeArchiveSeparation() {
    console.log('Running one-time archive separation...');

    const allLeads = JSON.parse(localStorage.getItem('insurance_leads') || '[]');
    const archivedLeads = JSON.parse(localStorage.getItem('archivedLeads') || '[]');
    const permanentArchive = JSON.parse(localStorage.getItem('PERMANENT_ARCHIVED_IDS') || '[]');

    // Build complete set of archived IDs
    const archivedIds = new Set();
    permanentArchive.forEach(id => archivedIds.add(String(id)));
    archivedLeads.forEach(lead => archivedIds.add(String(lead.id)));

    // Separate leads
    const activeOnly = [];
    const archivedOnly = [];

    allLeads.forEach(lead => {
        if (lead.archived === true || archivedIds.has(String(lead.id))) {
            // This is archived - should NOT be in insurance_leads
            archivedOnly.push(lead);
            console.log(`Moving to archived: ${lead.id} - ${lead.name}`);
        } else {
            // This is active
            activeOnly.push(lead);
        }
    });

    // Combine archived from both sources
    const allArchivedLeads = [...archivedLeads];
    archivedOnly.forEach(lead => {
        if (!allArchivedLeads.find(l => String(l.id) === String(lead.id))) {
            allArchivedLeads.push(lead);
        }
    });

    // Save separated data
    localStorage.setItem('insurance_leads', JSON.stringify(activeOnly));
    localStorage.setItem('archivedLeads', JSON.stringify(allArchivedLeads));

    console.log(`Separation complete: ${activeOnly.length} active, ${allArchivedLeads.length} archived`);
}

// Initialize Dashboard
document.addEventListener('DOMContentLoaded', function() {
    console.log('DOMContentLoaded - Initializing app');

    // Handle OAuth bank redirect back (e.g. PNC via Plaid)
    checkPlaidOAuthReturn();

    // Run one-time separation
    oneTimeArchiveSeparation();

    // Run initial cleanup
    cleanupDuplicateLeads();

    // Check if we have existing local data before loading from server
    const existingLeads = localStorage.getItem('insurance_leads');
    const existingArchived = localStorage.getItem('archivedLeads');

    // Load from server to ensure ViciDial and other server-added leads are visible
    // This ensures newly added ViciDial leads appear immediately after being synced
    loadLeadsFromServer().then(() => {
        console.log('✅ Initial server sync completed - ViciDial leads preserved');
    });

    // Load policies from server to ensure they're available for quote applications
    loadPoliciesFromServer().then(() => {
        console.log('✅ Policies loaded from server');
    });

    // DISABLED: Cleanup was causing leads to reset every 5 minutes
    // setInterval(() => {
    //     cleanupDuplicateLeads();
    // }, 300000); // Every 5 minutes - DISABLED to prevent resets

    // Initialize components
    initializeEventListeners();
    initializeAutomation();
    
    // Initialize renewals after a delay
    setTimeout(() => {
        loadUpcomingRenewals();
    }, 500);
    
    // Refresh renewals periodically
    setInterval(() => {
        loadUpcomingRenewals();
    }, 60000); // Every minute
    
    // Start real-time COI notification watcher
    setTimeout(() => {
        updateSidebarNotifBtn();
        startCOINotificationWatcher();
        startChatNotificationWatcher();
    }, 2000);

    const _initialHash = window.location.hash || '#dashboard';

    // If not on dashboard, blank out the pre-rendered HTML immediately so
    // the static dashboard stats don't flash before the real view loads.
    if (_initialHash !== '#dashboard') {
        const _dc = document.querySelector('.dashboard-content');
        if (_dc) _dc.innerHTML = '';
    }

    // Load the correct view immediately — no delay needed
    loadContent(_initialHash);
    updateActiveMenuItem(_initialHash);

    // Deep-link support: ?clientId=XXX auto-opens the client profile
    const _dlParams = new URLSearchParams(window.location.search);
    const _dlClientId = _dlParams.get('clientId');
    if (_dlClientId) {
        // Navigate to clients view, then open the profile once data is loaded
        if (_initialHash !== '#clients') {
            window.location.hash = '#clients';
        }
        const _openDeepLinkedClient = () => {
            if (typeof viewClient === 'function') {
                viewClient(_dlClientId);
                // Clean the URL without reloading
                window.history.replaceState({}, '', window.location.origin + window.location.pathname + '#clients');
            }
        };
        // Give clients view time to render before opening profile
        setTimeout(_openDeepLinkedClient, 1500);
    }
});

