function generatePolicyImportRows(policies, targetClientId) {
    if (!policies || policies.length === 0) {
        return `
            <tr>
                <td colspan="8" style="text-align: center; padding: 40px; color: #6b7280; font-style: italic;">
                    No policies found to import
                </td>
            </tr>
        `;
    }

    return policies.map(policy => {
        // Get policy type badge class
        const badgeClass = policy.policyType === 'Commercial Auto' ? 'badge-orange' : 'badge-blue';

        // Format dates (timezone-safe)
        const formatPolicyDate = (dateString) => {
            if (!dateString) return 'N/A';
            const date = new Date(dateString);
            // Use getMonth/getDate/getFullYear to avoid timezone conversion issues
            const month = date.getMonth() + 1; // getMonth() returns 0-11
            const day = date.getDate();
            const year = date.getFullYear();
            return `${month}/${day}/${year}`;
        };
        const effectiveDate = formatPolicyDate(policy.effectiveDate);
        const expirationDate = formatPolicyDate(policy.expirationDate);

        // Format premium
        const premium = policy.premium ?
            (typeof policy.premium === 'string' ? policy.premium : `$${parseFloat(policy.premium).toLocaleString()}`)
            : '$0';

        // Get client name
        const clientName = policy.clientName || policy.namedInsured || 'Unknown Client';

        // Get carrier name
        const carrierName = policy.carrier || policy.insuranceCarrier || 'N/A';

        return `
            <tr style="border-bottom: 1px solid #f3f4f6;">
                <td style="padding: 15px;">
                    <span class="policy-number" style="font-weight: 600; color: #1f2937;">${policy.policyNumber || 'N/A'}</span>
                </td>
                <td style="padding: 15px;">
                    <span class="policy-type-badge ${badgeClass}" style="
                        display: inline-block;
                        padding: 2px 8px;
                        border-radius: 12px;
                        font-size: 11px;
                        font-weight: 500;
                        background: ${badgeClass === 'badge-orange' ? '#fed7aa' : '#dbeafe'};
                        color: ${badgeClass === 'badge-orange' ? '#ea580c' : '#2563eb'};
                    ">${policy.policyType || 'Commercial Auto'}</span>
                </td>
                <td style="padding: 15px;">
                    <span class="client-name" style="font-weight: 500; color: #1f2937; word-break: break-word;">${clientName}</span>
                </td>
                <td style="padding: 15px;">
                    <span class="carrier-name" style="color: #374151;">${carrierName}</span>
                </td>
                <td style="padding: 15px;">
                    <span class="effective-date" style="color: #374151;">${effectiveDate}</span>
                </td>
                <td style="padding: 15px;">
                    <span class="expiration-date" style="color: #374151;">${expirationDate}</span>
                </td>
                <td style="padding: 15px;">
                    <span class="premium-amount" style="font-weight: 600; color: #059669;">${premium}</span>
                </td>
                <td style="padding: 15px; text-align: center;">
                    <button onclick="linkPolicyToClient('${policy.id}', '${targetClientId}')"
                            style="
                                padding: 8px 16px;
                                background: #10b981;
                                color: white;
                                border: none;
                                border-radius: 6px;
                                cursor: pointer;
                                font-size: 14px;
                                font-weight: 500;
                                transition: 0.2s;
                            "
                            onmouseover="this.style.background='#059669'"
                            onmouseout="this.style.background='#10b981'">
                        <i class="fas fa-link"></i> Import
                    </button>
                </td>
            </tr>
        `;
    }).join('');
}

function linkPolicyToClient(policyId, clientId) {
    // Get the policy and client data
    const policies = JSON.parse(localStorage.getItem('insurance_policies') || '[]');
    const clients = JSON.parse(localStorage.getItem('insurance_clients') || '[]');

    const policy = policies.find(p => p.id === policyId);
    const client = clients.find(c => c.id == clientId);

    if (!policy || !client) {
        showNotification('Policy or client not found', 'error');
        return;
    }

    // Create a copy of the policy and link it to the new client
    const linkedPolicy = {
        ...policy,
        id: `POL-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`, // New ID
        clientId: clientId,
        clientName: client.name,
        namedInsured: client.name,
        originalPolicyId: policyId // Keep reference to original
    };

    // Add the linked policy
    policies.push(linkedPolicy);
    localStorage.setItem('insurance_policies', JSON.stringify(policies));

    // Close the import modal
    closeImportPolicyModal();

    // Show success notification
    showNotification(`Policy ${policy.policyNumber} successfully imported for ${client.name}`, 'success');

    // Refresh the client view if we're still on the client page
    if (window.currentViewingClientId) {
        setTimeout(() => {
            viewClient(window.currentViewingClientId);
        }, 500);
    }
}

function closeImportPolicyModal() {
    const modal = document.getElementById('importPolicyModal');
    if (modal) {
        modal.remove();
    }
}

async function savePolicyForClient(clientId) {
    // This function saves the policy data from the tabbed modal and links it to the client
    
    // Get the policy data from the modal (using the same structure as savePolicy in policy-modal.js)
    const policyData = collectPolicyData();
    
    if (!policyData) {
        showNotification('Please fill in all required fields', 'error');
        return;
    }
    
    // Add client link and generate policy number
    policyData.clientId = clientId;
    policyData.id = Date.now();
    policyData.policyNumber = policyData.policyNumber || `POL-${new Date().getFullYear()}-${String(Date.now()).slice(-6)}`;
    policyData.createdAt = new Date().toISOString();
    
    // Get clients and update the specific client
    const clients = JSON.parse(localStorage.getItem('insurance_clients') || '[]');
    const clientIndex = clients.findIndex(c => c.id == clientId);
    
    if (clientIndex === -1) {
        showNotification('Client not found', 'error');
        return;
    }
    
    // Add policy to client
    if (!clients[clientIndex].policies || !Array.isArray(clients[clientIndex].policies)) {
        clients[clientIndex].policies = [];
    }
    clients[clientIndex].policies.push(policyData);
    
    // Update total premium
    const premium = policyData.financial?.['Annual Premium'] || policyData.premium || 0;
    clients[clientIndex].totalPremium = clients[clientIndex].policies.reduce((sum, p) => {
        const pPremium = p.financial?.['Annual Premium'] || p.premium || 0;
        return sum + (typeof pPremium === 'string' ? parseFloat(pPremium.replace(/[$,]/g, '')) || 0 : pPremium);
    }, 0);
    
    // Save updated clients
    localStorage.setItem('insurance_clients', JSON.stringify(clients));

    // Also save to global policies list (use insurance_policies for consistency)
    const policies = JSON.parse(localStorage.getItem('insurance_policies') || '[]');

    // Add client name to policy data for display
    policyData.clientName = clients[clientIndex].name;
    policyData.insured = policyData.insured || {};
    policyData.insured['Name/Business Name'] = clients[clientIndex].name;
    
    policies.push(policyData);
    localStorage.setItem('insurance_policies', JSON.stringify(policies));

    // Save to database via API calls
    try {
        console.log('💾 Saving policy to database...');

        // Save the policy to database
        const policyResponse = await fetch('/api/policies', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(policyData)
        });

        // Update the client in database with new policy count and premium
        const clientResponse = await fetch('/api/clients', {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                id: clientId,
                policies: clients[clientIndex].policies.length,
                totalPremium: clients[clientIndex].totalPremium
            })
        });

        if (policyResponse.ok && clientResponse.ok) {
            console.log('✅ Policy and client saved to database successfully');
        } else {
            console.warn('⚠️ Database save partially failed, but data is preserved in localStorage');
        }
    } catch (error) {
        console.warn('⚠️ Failed to save to database, but data is preserved in localStorage:', error);
    }

    // Close modal
    closePolicyModal();
    
    // Restore original save function
    if (window.originalSavePolicy) {
        window.savePolicy = window.originalSavePolicy;
        delete window.originalSavePolicy;
    }
    
    // Show success notification
    showNotification(`Policy ${policyData.policyNumber} added successfully!`, 'success');
    
    // Refresh the client view
    viewClient(clientId);
}

function collectPolicyData() {
    // Collect all the policy data from the tabbed form
    // This mirrors the structure used in policy-modal.js
    
    const data = {
        ...currentPolicyData, // Basic policy info from initial creation
        insured: {},
        contact: {},
        coverage: {},
        financial: {},
        vehicles: [],
        drivers: [],
        property: {},
        operations: {},
        documents: [],
        notes: {}
    };
    
    // Collect data from each active tab
    const tabs = document.querySelectorAll('.tab-content');
    tabs.forEach(tab => {
        if (!tab) return;

        const tabId = tab.id?.replace('-content', '');

        switch(tabId) {
            case 'overview':
                // Collect overview fields and update base policy data
                const overviewFields = {
                    'overview-policy-number': 'policyNumber',
                    'overview-carrier': 'carrier',
                    'overview-status': 'policyStatus',
                    'overview-effective-date': 'effectiveDate',
                    'overview-expiration-date': 'expirationDate',
                    'overview-premium': 'premium',
                    'overview-agent': 'agent',
                    'overview-dot-number': 'dotNumber',
                    'overview-mc-number': 'mcNumber'
                };

                Object.entries(overviewFields).forEach(([fieldId, dataKey]) => {
                    const field = document.getElementById(fieldId);
                    if (field && field.value) {
                        data[dataKey] = field.value;
                        if (dataKey === 'carrier') {
                            console.log('Collecting carrier:', field.value);
                        }
                    }
                });
                break;

            case 'insured':
                tab.querySelectorAll('input, select, textarea').forEach(field => {
                    if (field.id && field.value) {
                        const fieldName = field.previousElementSibling?.textContent?.replace(' *', '') || field.id;
                        data.insured[fieldName] = field.value;
                    }
                });
                break;
                
            case 'contact':
                tab.querySelectorAll('input, select, textarea').forEach(field => {
                    if (field.id && field.value) {
                        const fieldName = field.previousElementSibling?.textContent?.replace(' *', '') || field.id;
                        data.contact[fieldName] = field.value;
                    }
                });
                break;
                
            case 'coverage':
                tab.querySelectorAll('input, select, textarea').forEach(field => {
                    if (field.id && field.value) {
                        // Use the form-group's <label> for the key (not previousElementSibling which may be a hidden input)
                        const label = field.closest('.form-group')?.querySelector('label')?.textContent?.replace(' *', '').trim();
                        const fieldName = label || field.id;
                        data.coverage[fieldName] = field.value;
                    }
                });
                break;
                
            case 'financial':
                tab.querySelectorAll('input, select, textarea').forEach(field => {
                    if (field.id && field.value) {
                        const fieldName = field.previousElementSibling?.textContent?.replace(' *', '') || field.id;
                        data.financial[fieldName] = field.value;
                    }
                });
                break;
                
            case 'vehicles':
                // Collect vehicle and trailer data for commercial auto
                const vehicleEntries = tab.querySelectorAll('.vehicle-entry');
                vehicleEntries.forEach((entry, entryIndex) => {
                    const vehicle = {};
                    const inputs = entry.querySelectorAll('input, select');

                    console.log(`🚗 COLLECTING vehicle ${entryIndex + 1} data from ${inputs.length} inputs...`);

                    // Enhanced field mapping - capture all fields regardless of value
                    inputs.forEach((field, index) => {
                        let fieldName = '';
                        let fieldValue = field.value || '';

                        // First try placeholder-based mapping
                        const placeholder = (field.placeholder || '').toLowerCase();
                        const id = (field.id || '').toLowerCase();

                        if (placeholder.includes('year') || id.includes('year')) {
                            fieldName = 'year';
                        } else if (placeholder.includes('make') || id.includes('make')) {
                            fieldName = 'make';
                        } else if (placeholder.includes('model') || id.includes('model')) {
                            fieldName = 'model';
                        } else if (placeholder.includes('vin') || id.includes('vin')) {
                            fieldName = 'vin';
                        } else if (placeholder.includes('value') || id.includes('value')) {
                            fieldName = 'value';
                        } else if (placeholder.includes('deductible') || id.includes('deductible')) {
                            fieldName = 'deductible';
                        } else if (field.tagName === 'SELECT') {
                            fieldName = 'coverage';
                        } else {
                            // Fallback: use position-based mapping for unlabeled fields
                            const fieldMappings = ['year', 'make', 'model', 'vin', 'value', 'deductible'];
                            if (index < fieldMappings.length) {
                                fieldName = fieldMappings[index];
                            } else {
                                fieldName = `field_${index}`;
                            }
                        }

                        // ALWAYS capture the field, even if empty
                        vehicle[fieldName] = fieldValue;
                        console.log(`✅ Mapped field ${index}: ${fieldName} = "${fieldValue}"`);
                    });

                    // ALWAYS add the vehicle entry, even if some fields are empty
                    vehicle.vehicleNumber = entryIndex + 1;
                    vehicle.type = 'vehicle';
                    vehicle[''] = vehicle.year && vehicle.make && vehicle.model ?
                                  `${vehicle.year} ${vehicle.make} ${vehicle.model}`.trim() :
                                  `Vehicle ${entryIndex + 1}`;

                    data.vehicles.push(vehicle);
                    console.log(`🚗 SAVED vehicle ${entryIndex + 1}:`, JSON.stringify(vehicle, null, 2));
                });
                
                // Collect trailer data separately
                const trailerEntries = tab.querySelectorAll('.trailer-entry');
                trailerEntries.forEach((entry, entryIndex) => {
                    const trailer = {};
                    const inputs = entry.querySelectorAll('input, select');

                    console.log(`🚛 COLLECTING trailer ${entryIndex + 1} data from ${inputs.length} inputs...`);

                    // Enhanced field mapping - capture all fields regardless of value
                    inputs.forEach((field, index) => {
                        let fieldName = '';
                        let fieldValue = field.value || '';

                        // First try placeholder-based mapping
                        const placeholder = (field.placeholder || '').toLowerCase();
                        const id = (field.id || '').toLowerCase();

                        if (placeholder.includes('year') || id.includes('year')) {
                            fieldName = 'year';
                        } else if (placeholder.includes('make') || id.includes('make')) {
                            fieldName = 'make';
                        } else if (placeholder.includes('type') || id.includes('type') || placeholder.includes('model') || id.includes('model')) {
                            fieldName = 'model';
                        } else if (placeholder.includes('vin') || id.includes('vin')) {
                            fieldName = 'vin';
                        } else if (placeholder.includes('length') || id.includes('length')) {
                            fieldName = 'length';
                        } else if (placeholder.includes('value') || id.includes('value')) {
                            fieldName = 'value';
                        } else if (placeholder.includes('deductible') || id.includes('deductible')) {
                            fieldName = 'deductible';
                        } else if (field.tagName === 'SELECT') {
                            fieldName = 'coverage';
                        } else {
                            // Fallback: use position-based mapping for unlabeled fields
                            const fieldMappings = ['year', 'make', 'model', 'vin', 'length', 'value', 'deductible'];
                            if (index < fieldMappings.length) {
                                fieldName = fieldMappings[index];
                            } else {
                                fieldName = `field_${index}`;
                            }
                        }

                        // ALWAYS capture the field, even if empty
                        trailer[fieldName] = fieldValue;
                        console.log(`✅ Mapped trailer field ${index}: ${fieldName} = "${fieldValue}"`);
                    });

                    // ALWAYS add the trailer entry, even if some fields are empty
                    trailer.vehicleNumber = entryIndex + 1;
                    trailer.type = 'trailer';
                    trailer[''] = trailer.year && trailer.make && trailer.model ?
                                  `${trailer.year} ${trailer.make} ${trailer.model}`.trim() :
                                  `Trailer ${entryIndex + 1}`;

                    // Add to vehicles array but mark as trailer
                    data.vehicles.push(trailer);
                    console.log(`🚛 SAVED trailer ${entryIndex + 1}:`, JSON.stringify(trailer, null, 2));
                });
                break;
                
            case 'drivers':
                // Collect driver data
                const driverEntries = tab.querySelectorAll('.driver-entry');
                driverEntries.forEach(entry => {
                    const driver = {};
                    entry.querySelectorAll('input, select').forEach(field => {
                        if (field.value) {
                            const fieldName = field.previousElementSibling?.textContent?.replace(' *', '') || field.placeholder || 'unknown';
                            driver[fieldName] = field.value;
                        }
                    });
                    // Collect endorsements for CDL drivers
                    const endorsements = [];
                    entry.querySelectorAll('input[type="checkbox"]:checked').forEach(checkbox => {
                        endorsements.push(checkbox.parentElement.textContent.trim());
                    });
                    if (endorsements.length > 0) {
                        driver.endorsements = endorsements;
                    }
                    if (Object.keys(driver).length > 0) {
                        data.drivers.push(driver);
                    }
                });
                break;
                
            case 'notes':
                const notesField = tab.querySelector('textarea');
                if (notesField && notesField.value) {
                    data.notes.content = notesField.value;
                }
                break;
        }
    });
    
    return data;
}

