// Function to create quote applications for policies
window.createQuoteApplicationForPolicy = function(policyId) {
    console.log('Creating quote application for policy:', policyId);

    // Get policy data to pre-populate client information
    const policies = JSON.parse(localStorage.getItem('insurance_policies') || '[]');
    const policy = policies.find(p => String(p.id) === String(policyId));

    if (!policy) {
        alert('Policy not found');
        return;
    }

    // Extract client information from the policy's insured data
    const clientName = policy.insured?.['Name/Business Name'] ||
                      policy.insured?.['Primary Named Insured'] ||
                      policy.insuredName ||
                      'Unknown Client';

    // Extract vehicle data from policy
    const vehicleData = [];
    if (policy.vehicles && Array.isArray(policy.vehicles)) {
        policy.vehicles.forEach((vehicle, index) => {
            vehicleData.push({
                year: vehicle.Year || vehicle.year || '',
                make: vehicle.Make || vehicle.make || '',
                model: vehicle.Model || vehicle.model || '',
                vin: vehicle.VIN || vehicle.vin || '',
                type: vehicle.Type || vehicle.type || '',
                value: vehicle.Value || vehicle.value || '',
                radius: vehicle.Radius || vehicle.radius || ''
            });
        });
    }

    // Extract driver data from policy
    const driverData = [];
    if (policy.drivers && Array.isArray(policy.drivers)) {
        policy.drivers.forEach((driver, index) => {
            driverData.push({
                name: driver.name || driver['Full Name'] || '',
                dateOfBirth: driver.dateOfBirth || driver['Date of Birth'] || '',
                licenseNumber: driver.licenseNumber || driver['License Number'] || '',
                state: driver.state || '',
                yearsExperience: driver.yearsExperience || '',
                dateOfHire: driver.dateOfHire || '',
                accidents: driver.accidents || driver['# Accidents/Violations'] || ''
            });
        });
    }

    // Debug: Log full policy structure to find contact info location
    console.log('🔍 Full Policy Object:', policy);
    console.log('🔍 Policy insured data:', policy.insured);
    console.log('🔍 Policy contact fields:', {
        phone: policy.phone,
        email: policy.email,
        address: policy.address
    });

    // Check for contact info in different possible locations
    console.log('🔍 Checking contact field variations:', {
        contactInfo: policy.contactInfo,
        contact: policy.contact,
        clientInfo: policy.clientInfo,
        customerInfo: policy.customerInfo
    });

    // Search through all nested objects for contact information
    function findContactInfo(obj, searchTerms) {
        const results = {};
        for (const term of searchTerms) {
            for (const [key, value] of Object.entries(obj)) {
                if (typeof value === 'string' && key.toLowerCase().includes(term.toLowerCase()) && value.trim().length > 0) {
                    if (!results[term]) results[term] = value;
                }
                if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
                    const nested = findContactInfo(value, [term]);
                    if (nested[term] && !results[term]) results[term] = nested[term];
                }
            }
        }
        return results;
    }

    const foundContacts = findContactInfo(policy, ['phone', 'email', 'address']);
    console.log('🔍 Found contact information in policy:', foundContacts);

    // Extract contact information with multiple fallbacks
    const extractedPhone = policy.insured?.['Business Phone'] ||
                           policy.insured?.['Phone'] ||
                           policy.insured?.['Phone Number'] ||
                           policy.contactInfo?.phone ||
                           policy.contact?.phone ||
                           policy.phone ||
                           policy.businessPhone ||
                           foundContacts.phone ||
                           '';

    const extractedEmail = policy.insured?.['Email'] ||
                          policy.insured?.['Email Address'] ||
                          policy.contactInfo?.email ||
                          policy.contact?.email ||
                          policy.email ||
                          policy.emailAddress ||
                          foundContacts.email ||
                          '';

    const extractedAddress = policy.insured?.['Mailing Address'] ||
                            policy.insured?.['Address'] ||
                            policy.insured?.['Business Address'] ||
                            policy.contactInfo?.address ||
                            policy.contact?.address ||
                            policy.address ||
                            policy.mailingAddress ||
                            foundContacts.address ||
                            '';

    console.log('📞 Extracted contact info:', {
        phone: extractedPhone,
        email: extractedEmail,
        address: extractedAddress
    });

    // Extract DOT and MC numbers with multiple fallbacks
    const extractedDotNumber = policy.dotNumber ||
                              policy.insured?.['US DOT #'] ||
                              policy.insured?.['DOT Number'] ||
                              policy.dot ||
                              policy.usdot ||
                              '';

    const extractedMcNumber = policy.mcNumber ||
                             policy.insured?.['MC #'] ||
                             policy.insured?.['MC Number'] ||
                             policy.mc ||
                             '';

    console.log('🚛 Extracted DOT/MC info:', {
        dotNumber: extractedDotNumber,
        mcNumber: extractedMcNumber
    });

    // Create a temporary lead-like object for the policy-based quote application
    const tempLeadData = {
        id: `policy_${policyId}`,
        name: clientName,
        phone: extractedPhone,
        email: extractedEmail,
        address: extractedAddress,
        dotNumber: extractedDotNumber,
        mcNumber: extractedMcNumber,
        usdot: extractedDotNumber, // Also set usdot for compatibility
        policyId: policyId,
        isPolicyQuote: true,
        policyVehicles: vehicleData,
        policyDrivers: driverData
    };

    // Temporarily add this to leads storage so the quote application can find it
    const existingLeads = JSON.parse(localStorage.getItem('insurance_leads') || '[]');
    const tempLeads = [...existingLeads, tempLeadData];
    localStorage.setItem('insurance_leads', JSON.stringify(tempLeads));

    // Use the working quote application function from leads tab
    if (window.createQuoteApplicationSimple) {
        console.log('Using createQuoteApplicationSimple for policy:', policyId);
        window.createQuoteApplicationSimple(`policy_${policyId}`);

        // Clean up the temporary lead after a longer delay to allow for saving
        setTimeout(() => {
            const currentLeads = JSON.parse(localStorage.getItem('insurance_leads') || '[]');
            const cleanedLeads = currentLeads.filter(lead => lead.id !== `policy_${policyId}`);
            localStorage.setItem('insurance_leads', JSON.stringify(cleanedLeads));
            console.log('Cleaned up temporary policy lead');
        }, 5000); // Increased delay to 5 seconds
    } else if (window.createQuoteApplication) {
        console.log('Using createQuoteApplication for policy:', policyId);
        window.createQuoteApplication(`policy_${policyId}`);

        // Clean up the temporary lead after a longer delay to allow for saving
        setTimeout(() => {
            const currentLeads = JSON.parse(localStorage.getItem('insurance_leads') || '[]');
            const cleanedLeads = currentLeads.filter(lead => lead.id !== `policy_${policyId}`);
            localStorage.setItem('insurance_leads', JSON.stringify(cleanedLeads));
            console.log('Cleaned up temporary policy lead');
        }, 5000); // Increased delay to 5 seconds
    } else {
        alert('Quote application functionality not available. Please check that quote application scripts are loaded.');
        console.error('Available quote functions:', Object.keys(window).filter(k => k.toLowerCase().includes('quote')));
    }
};

