window.addCRMCOIEmailRecipientWithOptions = function() {
    const addInsuredCheck = document.getElementById('addInsuredCheck');
    const addAgentCheck = document.getElementById('addAgentCheck');

    // Get current policy data
    const currentPolicy = window.currentPolicy || {};

    let recipientsAdded = 0;

    // Add insured email if checkbox is checked
    if (addInsuredCheck.checked) {
        const insuredEmail = currentPolicy.contact?.['Email Address'] ||
                           currentPolicy.contact?.Email ||
                           currentPolicy.contact?.['Email'] ||
                           currentPolicy.insured?.Email ||
                           currentPolicy.policies?.[0]?.contact?.['Email Address'] ||
                           currentPolicy.policies?.[0]?.contact?.Email || '';

        if (insuredEmail) {
            addCRMCOIEmailRecipient();
            const newRows = document.querySelectorAll('.crm-coi-email-recipient-row');
            const lastRow = newRows[newRows.length - 1];
            const emailInput = lastRow.querySelector('.crm-coi-email-recipient');
            emailInput.value = insuredEmail;
            emailInput.placeholder = `${currentPolicy.clientName || currentPolicy.insured_name || 'Insured'} (Insured)`;
            recipientsAdded++;
        }
        addInsuredCheck.checked = false; // Uncheck after use
    }

    // Add agent email if checkbox is checked
    if (addAgentCheck.checked) {
        // Try to get agent email from policy, then fall back to name→email map
        const _agentEmailMap = { hunter: 'Hunter@vigagency.com', grant: 'Grant@vigagency.com', maureen: 'Maureen.corp@vigagency.com', carson: 'Carson@vigagency.com' };
        const _agentKey = (currentPolicy.agent || currentPolicy.assignedTo || '').toLowerCase().trim();
        const agentEmail = currentPolicy.agentEmail || _agentEmailMap[_agentKey] || '';

        addCRMCOIEmailRecipient();
        const newRows = document.querySelectorAll('.crm-coi-email-recipient-row');
        const lastRow = newRows[newRows.length - 1];
        const emailInput = lastRow.querySelector('.crm-coi-email-recipient');
        emailInput.value = agentEmail;
        emailInput.placeholder = `${currentPolicy.agent || 'Agent'} (Agent)`;
        recipientsAdded++;
        addAgentCheck.checked = false; // Uncheck after use
    }

    // If neither checkbox is checked, add a blank recipient
    if (recipientsAdded === 0) {
        addCRMCOIEmailRecipient();
    }
};

window.handleCheckboxChange = function(type, silent) {
    const checkbox = document.getElementById(type === 'insured' ? 'addInsuredCheck' : 'addAgentCheck');
    const dataAttr = type === 'insured' ? 'insured' : 'agent';

    if (checkbox.checked) {
        const currentPolicy = window.currentCOIPolicy || window.currentPolicy || {};

        if (type === 'insured') {
            const insuredEmail = currentPolicy.contact?.['Email Address'] ||
                               currentPolicy.contact?.Email ||
                               currentPolicy.contact?.['Email'] ||
                               currentPolicy.insured?.Email ||
                               currentPolicy.policies?.[0]?.contact?.['Email Address'] ||
                               currentPolicy.policies?.[0]?.contact?.Email || '';

            if (insuredEmail) {
                addCRMCOIEmailRecipient();
                const newRows = document.querySelectorAll('.crm-coi-email-recipient-row');
                const lastRow = newRows[newRows.length - 1];
                lastRow.dataset.addedBy = 'insured';
                const emailInput = lastRow.querySelector('.crm-coi-email-recipient');
                emailInput.value = insuredEmail;
                emailInput.placeholder = `${currentPolicy.clientName || currentPolicy.insured_name || 'Insured'} (Insured)`;
            } else {
                checkbox.checked = false;
                if (!silent) alert('No email address found in Contact Information for this policy.');
            }
        } else if (type === 'agent') {
            const _agentEmailMap = { hunter: 'Hunter@vigagency.com', grant: 'Grant@vigagency.com', maureen: 'Maureen.corp@vigagency.com', carson: 'Carson@vigagency.com' };
            // Primary: read from policy object
            let _agentName = currentPolicy.agent || currentPolicy.assignedTo || '';
            // Fallback: scrape from overview tab only (not edit form labels)
            if (!_agentName) {
                const _overviewTab = document.getElementById('overview-view-content');
                if (_overviewTab) {
                    const _labels = _overviewTab.querySelectorAll('label');
                    for (const _lbl of _labels) {
                        if (_lbl.textContent.trim() === 'Agent') {
                            const _p = _lbl.nextElementSibling;
                            if (_p && _p.textContent.trim() && _p.textContent.trim() !== 'N/A') {
                                _agentName = _p.textContent.trim();
                                break;
                            }
                        }
                    }
                }
            }
            const _agentRaw = _agentName.toLowerCase().trim();
            const _agentKey = Object.keys(_agentEmailMap).find(k => _agentRaw.includes(k));
            const agentEmail = currentPolicy.agentEmail || (_agentKey ? _agentEmailMap[_agentKey] : '') || '';

            if (agentEmail) {
                addCRMCOIEmailRecipient();
                const newRows = document.querySelectorAll('.crm-coi-email-recipient-row');
                const lastRow = newRows[newRows.length - 1];
                lastRow.dataset.addedBy = 'agent';
                const emailInput = lastRow.querySelector('.crm-coi-email-recipient');
                emailInput.value = agentEmail;
                emailInput.placeholder = `${_agentName || 'Agent'} (Agent)`;
            } else {
                checkbox.checked = false;
                if (!silent) alert('No agent email found for this policy.');
            }
        }
    } else {
        // Unchecked — remove the row that was added by this checkbox
        const container = document.getElementById('crmCoiEmailRecipientsContainer');
        const rows = container.querySelectorAll('.crm-coi-email-recipient-row');
        if (rows.length > 1) {
            const toRemove = container.querySelector(`.crm-coi-email-recipient-row[data-added-by="${dataAttr}"]`);
            if (toRemove) toRemove.remove();
        }
    }
};

window.removeCRMCOIEmailRecipient = function(button) {
    const container = document.getElementById('crmCoiEmailRecipientsContainer');
    const rows = container.querySelectorAll('.crm-coi-email-recipient-row');

    // Don't allow removing if there's only one row
    if (rows.length > 1) {
        button.parentElement.remove();
    } else {
        alert('At least one email recipient is required.');
    }
};

// CRM COI overlay function - adds certificate holder and date to COI document
window.createCRMCOIWithTextOverlay = async function(coiDocument, holderType, policy, certificateHolder) {
    return new Promise((resolve) => {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        const img = new Image();

        img.onload = function() {
            canvas.width = img.width;
            canvas.height = img.height;

            // Draw the original COI image
            ctx.drawImage(img, 0, 0);

            // Set up text styling
            ctx.fillStyle = '#000000';
            ctx.font = '14px Arial, sans-serif';
            ctx.textAlign = 'left';

            // Certificate holder text position (bottom left area)
            const startX = 50;
            const startY = 900;

            if (holderType === 'business') {
                // Use client information
                const clientName = policy.clientName || policy.insured_name || 'Unknown Client';
                ctx.fillText(clientName, startX, startY);
                console.log('📝 Overlaid business certificate holder:', clientName);
            } else {
                // Use third-party information from certificateHolder string
                const lines = certificateHolder.split('\n');
                lines.forEach((line, index) => {
                    if (line.trim()) {
                        ctx.fillText(line.trim(), startX, startY + (index * 20));
                    }
                });
                console.log('📝 Overlaid third-party certificate holder:', lines[0] || 'Unknown');
            }

            // Add current date overlay in top right
            const currentDate = new Date().toLocaleDateString();
            console.log('🖼️ Canvas dimensions:', canvas.width, 'x', canvas.height);

            // Position for date field (top right area of ACORD form)
            let dateX = Math.min(canvas.width - 100, 695); // Ensure it fits within canvas
            const dateY = 57.5;

            // Ensure the date position is within canvas bounds
            if (dateX + 100 > canvas.width) {
                dateX = canvas.width - 100;
            }

            ctx.font = '12px Arial, sans-serif';
            ctx.fillText(currentDate, dateX, dateY);
            console.log('📅 Overlaid current date:', currentDate, 'at position:', dateX, dateY);
            console.log('📅 Date text bounds: X=' + dateX + ', Y=' + dateY + ', within canvas=' + (dateX + 100 <= canvas.width));

            // Add checkmarks for checked boxes based on current form state - adjusted Y positions up by 12 pixels
            const checkboxMapping = {
                'glCheck': { x: 47, y: 378 },
                'glOccurrence': { x: 150, y: 394 },
                'glClaimsMade': { x: 65, y: 394 },
                'autoAny': { x: 47, y: 503 },
                'autoOwned': { x: 47, y: 518 },
                'autoScheduled': { x: 135, y: 518 },
                'autoHired': { x: 47, y: 534 },
                'autoNonOwned': { x: 135, y: 534 },
                'umbrella': { x: 47, y: 565 },
                'excess': { x: 47, y: 581 },
                'wcStatute': { x: 552, y: 612 },
                'wcOther': { x: 618, y: 612 },
                'aggPolicy': { x: 47, y: 456 },
                'aggProject': { x: 103, y: 456 },
                'aggLocation': { x: 159, y: 456 },
                'aggOther': { x: 47, y: 472 }
            };

            // Draw checkmarks for checked boxes
            Object.entries(checkboxMapping).forEach(([fieldName, position]) => {
                const checkboxElement = document.getElementById(`field_${fieldName}`);
                if (checkboxElement && checkboxElement.checked) {
                    // Draw a checkmark
                    ctx.fillStyle = '#000000';
                    ctx.font = 'bold 14px Arial, sans-serif';
                    ctx.fillText('✓', position.x + 2, position.y + 12);
                    console.log(`☑️ Drew checkmark for ${fieldName} at position ${position.x}, ${position.y}`);
                }
            });

            // Convert canvas to blob
            canvas.toBlob((blob) => {
                console.log('✅ Created COI with text overlay, size:', blob.size, 'bytes');
                resolve(blob);
            }, 'image/png', 0.95);
        };

        img.onerror = function(error) {
            console.error('❌ Error loading COI image for overlay:', error);
            resolve(null);
        };

        // Load the COI image
        img.src = coiDocument.dataUrl;
    });
};

window.submitCRMCOIModal = async function() {
    const form = document.getElementById('crmCOIModalForm');
    const submitBtn = document.querySelector('#crmCOIModal .btn-submit');

    // Get form values
    const holderType = document.querySelector('input[name="crmHolderType"]:checked').value;

    // Collect all email recipients
    const emailInputs = document.querySelectorAll('.crm-coi-email-recipient');
    const emails = Array.from(emailInputs).map(input => input.value.trim()).filter(email => email);

    console.log(`📧 Found ${emailInputs.length} email input fields`);
    console.log(`📧 Collected ${emails.length} valid email addresses:`, emails);

    if (emails.length === 0) {
        alert('Please enter at least one email address');
        return;
    }

    let certificateHolder = '';

    if (holderType === 'third-party') {
        const holderName = document.getElementById('crmHolderName').value.trim();
        const holderAddress = document.getElementById('crmHolderAddress').value.trim();
        const holderCity = document.getElementById('crmHolderCity').value.trim();

        if (!holderName || !holderAddress) {
            alert('Please fill in certificate holder name and address');
            return;
        }

        certificateHolder = holderName + '\n' + holderAddress;
        if (holderCity) {
            certificateHolder += '\n' + holderCity;
        }
    }

    // Disable button and show loading
    submitBtn.disabled = true;
    submitBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Sending...';

    // Get policy data from the modal
    const policyBanner = document.querySelector('#crmCOIModal .policy-info-banner strong');
    const policyText = policyBanner ? policyBanner.nextSibling.textContent.trim() : '';
    const policyId = policyText.split(' - ')[0] || 'Unknown';

    // Find the current policy data for email formatting
    let currentPolicy = null;

    // Try multiple sources to find the policy
    try {
        // First: check window.allPolicies
        if (window.allPolicies && Array.isArray(window.allPolicies)) {
            currentPolicy = window.allPolicies.find(p => p.id === policyId || p.policyNumber === policyId || p.policy_number === policyId);
        }

        // Second: check localStorage
        if (!currentPolicy) {
            const storedPolicies = JSON.parse(localStorage.getItem('insurance_policies') || '[]');
            currentPolicy = storedPolicies.find(p => p.id === policyId || p.policyNumber === policyId || p.policy_number === policyId);
        }

        // Third: extract from modal text if available
        if (!currentPolicy && policyText.includes(' - ')) {
            const parts = policyText.split(' - ');
            currentPolicy = {
                policy_number: policyId,
                clientName: parts[1] || 'N/A',
                carrier: parts[2] || 'N/A'
            };
        }

        console.log('🔍 Found current policy:', currentPolicy);
    } catch (error) {
        console.log('⚠️ Error finding policy:', error);
        // Create minimal fallback policy
        currentPolicy = {
            policy_number: policyId,
            clientName: 'N/A',
            carrier: 'N/A'
        };
    }

    try {
        // First, try to get the COI document for this policy
        let coiDocument = null;

        // Collect all IDs this policy might be stored under
        const fullPolicyId = currentPolicy?.id || '';
        const policyNumber = currentPolicy?.policyNumber || policyId;
        const coiSearchIds = [policyId, fullPolicyId, policyNumber].filter(Boolean);
        console.log('🔍 Looking for COI document for policy:', policyId, '| search IDs:', coiSearchIds);

        // 1. Check insurance_policies localStorage — filter to the actual policy
        const storedPolicies = JSON.parse(localStorage.getItem('insurance_policies') || '[]');
        for (const policy of storedPolicies) {
            const matches = coiSearchIds.some(id =>
                id && (policy.policyNumber === id || policy.id === id ||
                       (policy.policyNumber && policy.policyNumber.trim() === id.trim()) ||
                       (policy.id && policy.id.trim() === id.trim()))
            );
            if (matches && policy.coiDocuments && Array.isArray(policy.coiDocuments) && policy.coiDocuments.length > 0) {
                console.log('📋 Found COI in insurance_policies for:', policy.policyNumber || policy.id);
                coiDocument = policy.coiDocuments[policy.coiDocuments.length - 1]; // Use latest
                break;
            }
        }

        // 2. Check legacy policy_coi_documents localStorage
        if (!coiDocument) {
            const legacyCOIs = JSON.parse(localStorage.getItem('policy_coi_documents') || '[]');
            const match = legacyCOIs.find(doc => coiSearchIds.some(id => id && doc.policyId === id));
            if (match) {
                console.log('📋 Found COI in policy_coi_documents for policy:', match.policyId);
                coiDocument = match;
            }
        }

        // 3. Try to capture the current ACORD canvas directly (works even if Save wasn't clicked)
        if (!coiDocument) {
            try {
                const canvas = document.getElementById('realPdfCanvas') ||
                               document.querySelector('#acordViewerContainer canvas') ||
                               document.querySelector('.pdf-canvas-container canvas');
                if (canvas && canvas.width > 100) {
                    console.log('📸 Capturing current ACORD canvas for attachment...');
                    const dataUrl = canvas.toDataURL('image/png', 0.95);
                    if (dataUrl && dataUrl.length > 1000) {
                        coiDocument = { dataUrl, name: `COI_${policyId}.png`, type: 'image/png' };
                        console.log('✅ Captured COI from live canvas, size:', dataUrl.length);
                    }
                }
            } catch (canvasErr) {
                console.log('⚠️ Canvas capture failed:', canvasErr.message);
            }
        }

        // 4. Fall back to API
        if (!coiDocument) {
            try {
                // Try both the policy number and full ID
                for (const searchId of coiSearchIds) {
                    console.log('🔍 Fetching COI document from API for:', searchId);
                    const coiResponse = await fetch(`https://162-220-14-239.nip.io/api/coi/${encodeURIComponent(searchId)}`);
                    if (coiResponse.ok) {
                        coiDocument = await coiResponse.json();
                        console.log('✅ Found COI document via API:', coiDocument.name || 'unnamed');
                        break;
                    }
                }
            } catch (error) {
                console.log('⚠️ Could not fetch COI from API:', error.message);
            }
        }

        // Apply COI overlay with certificate holder and date (like website does)
        let finalCoiDocument = null;
        console.log('🔍 Debug coiDocument check:', coiDocument ? 'exists' : 'null', coiDocument?.dataUrl ? 'has dataUrl' : 'no dataUrl');
        if (coiDocument && coiDocument.dataUrl) {
            try {
                console.log('✅ Using COI overlay function to add certificate holder and date...');
                finalCoiDocument = await window.createCRMCOIWithTextOverlay(coiDocument, holderType, currentPolicy, certificateHolder);
                console.log('📎 COI document modified with text overlay, size:', finalCoiDocument ? finalCoiDocument.size : 'null/undefined');
                console.log('🔍 Debug finalCoiDocument after creation:', finalCoiDocument);
            } catch (error) {
                console.error('❌ Error creating COI with overlay:', error);
                // Fallback to original document
                try {
                    const response = await fetch(coiDocument.dataUrl);
                    finalCoiDocument = await response.blob();
                    console.log('📎 Fallback: Using original COI document, size:', finalCoiDocument.size);
                } catch (fallbackError) {
                    console.error('❌ Error accessing COI document:', fallbackError);
                }
            }
        }

        // Prepare the COI request data as FormData (not JSON) to match the API
        const formData = new FormData();

        // Set sender email
        formData.append('from', 'contact@vigagency.com');

        // Pass agent and united flag so backend can pick the correct sender address
        const policyAgent = currentPolicy?.agent || '';
        formData.append('agent', policyAgent);
        formData.append('united', currentPolicy?.united ? 'true' : 'false');

        // Set recipient emails (all emails from the array)
        formData.append('to', emails.join(', '));

        // Set email subject - match website format exactly
        const subjectText = `Certificate of Insurance - ${currentPolicy?.clientName || currentPolicy?.insured_name || 'N/A'} - Policy ${policyId}`;
        formData.append('subject', subjectText);

        // Set policy ID
        formData.append('policyId', policyId);

        // Build email message body - match website format exactly
        let messageBody = `Dear Certificate Holder,

Please find attached your Certificate of Insurance for ${currentPolicy?.clientName || currentPolicy?.insured_name || 'N/A'}.

Policy Number: ${policyId}
Insured: ${currentPolicy?.clientName || currentPolicy?.insured_name || 'N/A'}
Carrier: ${currentPolicy?.carrier || 'N/A'}

Certificate Holder:
${certificateHolder}`;

        formData.append('message', messageBody);

        // Add COI document as attachment if available - Convert to PDF
        console.log('🔍 Debug finalCoiDocument before attachment:', finalCoiDocument ? finalCoiDocument.size + ' bytes' : 'null/undefined');
        if (finalCoiDocument) {
            console.log('📎 Converting modified COI document to PDF...');

            // Convert PNG blob to PDF
            try {
                const pdfResult = await convertCOItoPDF(finalCoiDocument, `COI_Certificate_${policyId}_${Date.now()}`);
                if (pdfResult) {
                    formData.append('attachment', pdfResult.blob, pdfResult.filename);
                    console.log('📎 PDF COI document attached as:', pdfResult.filename);
                } else {
                    // Fallback to PNG if PDF conversion fails
                    const fileName = `COI_Certificate_${policyId}_${Date.now()}.png`;
                    formData.append('attachment', finalCoiDocument, fileName);
                    console.log('📎 Fallback: Modified COI document attached as PNG:', fileName);
                }
            } catch (error) {
                console.error('❌ PDF conversion failed, using PNG fallback:', error);
                const fileName = `COI_Certificate_${policyId}_${Date.now()}.png`;
                formData.append('attachment', finalCoiDocument, fileName);
                console.log('📎 Fallback: Modified COI document attached as PNG:', fileName);
            }
        } else if (coiDocument) {
            try {
                console.log('📎 Attaching original COI document:', coiDocument.name || 'COI Document');
                console.log('🔍 Debug coiDocument for fallback:', coiDocument);

                let coiBlob = null;

                // Try to get the COI document blob from different sources
                if (coiDocument.dataUrl) {
                    // Convert dataUrl to blob
                    const response = await fetch(coiDocument.dataUrl);
                    coiBlob = await response.blob();
                    console.log('✅ Created blob from dataUrl, size:', coiBlob.size);
                } else if (coiDocument.url) {
                    // Fetch from URL
                    const response = await fetch(coiDocument.url);
                    coiBlob = await response.blob();
                    console.log('✅ Created blob from URL, size:', coiBlob.size);
                } else if (coiDocument.file) {
                    // Use file directly
                    coiBlob = coiDocument.file;
                    console.log('✅ Using file directly, size:', coiBlob.size);
                }

                if (coiBlob) {
                    console.log('📎 Converting original COI document to PDF...');
                    try {
                        const pdfResult = await convertCOItoPDF(coiBlob, `COI_Certificate_${policyId}`);
                        if (pdfResult) {
                            formData.append('attachment', pdfResult.blob, pdfResult.filename);
                            console.log('📎 PDF COI document attached as:', pdfResult.filename);
                        } else {
                            // Fallback to original format if PDF conversion fails
                            const fileName = coiDocument.name || `COI_Certificate_${policyId}.png`;
                            formData.append('attachment', coiBlob, fileName);
                            console.log('📎 Fallback: COI document attached as:', fileName);
                        }
                    } catch (error) {
                        console.error('❌ PDF conversion failed, using original format:', error);
                        const fileName = coiDocument.name || `COI_Certificate_${policyId}.png`;
                        formData.append('attachment', coiBlob, fileName);
                        console.log('📎 Fallback: COI document attached as:', fileName);
                    }
                } else {
                    console.log('⚠️ Could not create blob from COI document');
                }
            } catch (error) {
                console.error('❌ Error attaching COI document:', error);
            }
        } else {
            console.log('⚠️ No COI document found to attach');
            console.log('🔍 Debug: finalCoiDocument is null and coiDocument is:', coiDocument ? 'exists but no valid data' : 'null');
        }

        console.log('Submitting COI request via FormData to:', 'https://162-220-14-239.nip.io/api/coi/send-request');
        console.log('FormData contents:', {
            from: 'contact@vigagency.com',
            to: emails.join(', '),
            subject: subjectText,
            policyId: policyId,
            messagePreview: messageBody.substring(0, 200) + '...',
            hasAttachment: !!coiDocument,
            totalRecipients: emails.length
        });

        // Send to the same endpoint as client portal using FormData
        const response = await fetch('https://162-220-14-239.nip.io/api/coi/send-request', {
            method: 'POST',
            body: formData  // Send as FormData, not JSON
        });

        const data = await response.json();

        if (data.success) {
            alert('Certificate of Insurance sent successfully!\n\n' + (data.message || 'The certificate has been emailed.'));
            closeCRMCOIModal();
        } else {
            alert('Error sending COI:\n\n' + (data.error || 'An unexpected error occurred. Please try again.'));
            submitBtn.disabled = false;
            submitBtn.innerHTML = '<i class="fas fa-envelope"></i> Send Certificate';
        }

    } catch (error) {
        console.error('Error submitting COI request:', error);
        alert('Connection Error\n\nUnable to connect to the server. Please try again.\n\nError: ' + error.message);
        submitBtn.disabled = false;
        submitBtn.innerHTML = '<i class="fas fa-envelope"></i> Send Certificate';
    }
};

